import React, { useState } from 'react';
import './App.css';

function App() {
  // GEREKSİNİM TAKİBİ İÇİN STATE'LER
  const [view, setView] = useState('login'); // login, register, dashboard, profile
  const [filter, setFilter] = useState('Hepsi'); // Gereksinim 7 (Filtreleme)
  const [points, setPoints] = useState(1250); // Gereksinim 11 (Puan Kazanma)
  const [streak] = useState(5); // Gereksinim 15 (Günlük Seri)
  const [workouts, setWorkouts] = useState([
    { id: 1, name: 'Sabah Kardiyosu', date: '24 Mart', xp: 150 },
    { id: 2, name: 'Güç Antrenmanı', date: '25 Mart', xp: 200 }
  ]);

  // GEREKSİNİM 17: Antrenman Kaydını Silme
  const deleteWorkout = (id) => {
    setWorkouts(workouts.filter(w => w.id !== id));
  };

  // GEREKSİNİM 11: Puan Kazanma (Simülasyon)
  const earnPoints = () => {
    setPoints(prev => prev + 50);
    alert("Tebrikler! 50 XP Kazandın.");
  };

  // --- GİRİŞ VE KAYIT EKRANLARI (Gereksinim 1) ---
  if (view === 'login' || view === 'register') {
    return (
      <div className="pro-login-page">
        <div className="glass-card">
          <div className="pro-logo">FIT<span>STACK</span></div>
          <h2>{view === 'login' ? 'Tekrar Hoş Geldin' : 'Bize Katıl'}</h2>

          <form className="pro-form" onSubmit={(e) => { e.preventDefault(); setView('dashboard'); }}>
            {view === 'register' && (
              <div className="pro-input">
                <input type="text" placeholder="Ad Soyad" required />
              </div>
            )}
            <div className="pro-input">
              <input type="text" placeholder="Kullanıcı Adı" required />
            </div>
            <div className="pro-input">
              <input type="password" placeholder="Şifre" required />
            </div>
            <button type="submit" className="pro-btn-main">
              {view === 'login' ? 'Giriş Yap' : 'Kayıt Ol (Gereksinim 1)'}
            </button>
          </form>

          <p className="toggle-text">
            {view === 'login' ? 'Hesabın yok mu?' : 'Zaten üye misin?'}
            <span onClick={() => setView(view === 'login' ? 'register' : 'login')}>
              {view === 'login' ? ' Şimdi Kayıt Ol' : ' Giriş Yap'}
            </span>
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="pro-app">
      {/* SOL MENÜ (SIDEBAR) */}
      <nav className="pro-sidebar">
        <div className="pro-logo">FIT<span>STACK</span></div>
        <ul className="pro-menu">
          <li className={view === 'dashboard' ? 'active' : ''} onClick={() => setView('dashboard')}>🏠 Dashboard</li>
          <li className={view === 'profile' ? 'active' : ''} onClick={() => setView('profile')}>👤 Profilim</li>
        </ul>

        {/* GEREKSİNİM 13: Rozet Kazanma */}
        <div className="badges-widget">
          <p>ROZETLERİN (Gereksinim 13)</p>
          <div className="badge-icons">🏆 🥇 💎</div>
        </div>

        <div className="pro-user-bottom">
          <div className="avatar">S</div>
          <div className="user-info">
            <p>Sema Yılmaz</p>
            <span onClick={() => setView('login')}>Güvenli Çıkış</span>
          </div>
        </div>
      </nav>

      {/* ANA İÇERİK ALANI */}
      <main className="pro-content">
        <header className="pro-header">
          <div>
            <h1>{view === 'dashboard' ? 'Dashboard' : 'Profil Ayarları'}</h1>
            <p className="date-text">3 Nisan 2026, Cuma</p>
          </div>
          {/* GEREKSİNİM 15: Günlük Seri */}
          <div className="streak-tag">🔥 {streak} GÜNLÜK SERİ</div>
        </header>

        {view === 'dashboard' ? (
          <div className="dashboard-grid">
            {/* PUAN KARTI (Gereksinim 11) */}
            <div className="stat-card-pro">
              <label>TOPLAM PUAN (XP)</label>
              <div className="xp-value">{points}</div>
              <div className="xp-bar"><div className="xp-fill" style={{width: '65%'}}></div></div>
              <button className="earn-btn" onClick={earnPoints}>+ XP Kazan</button>
            </div>

            {/* FİLTRELEME VE PROGRAMLAR (Gereksinim 7) */}
            <section className="programs-section">
              <div className="section-header">
                <h3>Programlar (Gereksinim 7)</h3>
                <select className="pro-select" onChange={(e) => setFilter(e.target.value)}>
                  <option value="Hepsi">Tüm Seviyeler</option>
                  <option value="Başlangıç">Başlangıç</option>
                  <option value="İleri">İleri</option>
                </select>
              </div>
              <div className="pro-grid-list">
                <div className="pro-item-card">
                  <span>Başlangıç</span>
                  <h4>Yağ Yakımı 101</h4>
                  <button onClick={() => alert("Antrenman Kaydı Oluşturuldu! (Gereksinim 9)")}>KAYDET</button>
                </div>
              </div>
            </section>

            {/* ANTRENMAN LİSTESİ VE SİLME (Gereksinim 9 & 17) */}
            <section className="workouts-section">
              <h3>Son Antrenmanlar (Gereksinim 9)</h3>
              {workouts.map(w => (
                <div className="workout-row" key={w.id}>
                  <div>
                    <h4>{w.name}</h4>
                    <small>{w.date}</small>
                  </div>
                  <div className="row-right">
                    <span className="xp-badge">+{w.xp} XP</span>
                    <button className="del-icon" onClick={() => deleteWorkout(w.id)}>🗑️</button>
                  </div>
                </div>
              ))}
            </section>
          </div>
        ) : (
          /* PROFİL VE HESAP SİLME (Gereksinim 3 & 5) */
          <div className="profile-view">
            <div className="profile-card-large">
              <h3>Profil Bilgileri (Gereksinim 3)</h3>
              <p><strong>E-posta:</strong> sema@fitstack.com</p>
              <p><strong>Durum:</strong> Aktif Üye</p>
              <div className="danger-zone">
                <h4>Hesap Yönetimi</h4>
                <p>Hesabınızı sildiğinizde geri dönemezsiniz.</p>
                <button className="delete-btn-pro" onClick={() => alert("Hesap Silme Talebi Alındı! (Gereksinim 5)")}>
                  HESABI KALICI SİL
                </button>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
